class DSU(val size: Int) {
  val parent = Array.ofDim[Int](size + 1)
  val rank = Array.ofDim[Int](size + 1)

  def this(size: Int) = this(size)

  def init(): Unit = {
    for (i <- 1 to size) {
      parent(i) = i
      rank(i) = 1
    }
  }

  def find(x: Int): Int = {
    if (parent(x) != x) {
      parent(x) = find(parent(x))
    }
    parent(x)
  }

  def union(x: Int, y: Int): Unit = {
    val xRoot = find(x)
    val yRoot = find(y)
    if (xRoot == yRoot) return
    if (rank(xRoot) < rank(yRoot)) {
      parent(xRoot) = yRoot
    } else {
      parent(yRoot) = xRoot
      if (rank(xRoot) == rank(yRoot)) {
        rank(xRoot) += 1
      }
    }
  }
}

def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
  val dsu = new DSU(c.toInt)
  dsu.init()
  for (u <- connections) {
    val uInt = u(0).toInt
    val vInt = u(1).toInt
    dsu.union(uInt, vInt)
  }

  val componentTreeset = scala.collection.mutable.HashMap[Int, scala.collection.mutable.TreeSet[Int]]()

  for (node <- 1 to c.toInt) {
    val root = dsu.find(node)
    if (!componentTreeset.contains(root)) {
      componentTreeset(root) = scala.collection.mutable.TreeSet[Int]()
    }
    componentTreeset(root) += node
  }

  val online = Array.fill(c.toInt + 1)(true)
  val res = scala.collection.mutable.ArrayBuffer[Long]()

  for (query <- queries) {
    val typeQ = query(0)
    val x = query(1).toInt
    if (typeQ == 1) {
      if (online(x)) {
        res += x.toLong
      } else {
        val root = dsu.find(x)
        val treeSet = componentTreeset.get(root)
        if (treeSet.isEmpty) {
          res += -1.toLong
        } else {
          val min = treeSet.min
          res += min.toLong
        }
      }
    } else {
      online(x) = false
      val root = dsu.find(x)
      componentTreeset(root).remove(x)
    }
  }

  res.toArray
}
