import scala.collection.mutable._

class DSU(val size: Int) {
  val parent = Array.fill(size + 1)(0)
  val rank = Array.fill(size + 1)(1)

  def find(x: Int): Int = {
    if (parent(x) != x) {
      parent(x) = find(parent(x))
    }
    parent(x)
  }

  def union(x: Int, y: Int): Unit = {
    val xRoot = find(x)
    val yRoot = find(y)
    if (xRoot == yRoot) return
    if (rank(xRoot) < rank(yRoot)) {
      parent(xRoot) = yRoot
    } else {
      parent(yRoot) = xRoot
      if (rank(xRoot) == rank(yRoot)) {
        rank(xRoot) += 1
      }
    }
  }
}

