import heapq
from collections import defaultdict

def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    class DSU:
        def __init__(self, size):
            self.parent = list(range(size + 1))  # 1-based indexing
            self.rank = [1] * (size + 1)

        def find(self, x):
            if self.parent[x] != x:
                self.parent[x] = self.find(self.parent[x])
            return self.parent[x]

        def union(self, x, y):
            x_root = self.find(x)
            y_root = self.find(y)
            if x_root == y_root:
                return
            if self.rank[x_root] < self.rank[y_root]:
                self.parent[x_root] = y_root
            else:
                self.parent[y_root] = x_root
                if self.rank[x_root] == self.rank[y_root]:
                    self.rank[x_root] += 1

    dsu = DSU(c)
    for u, v in connections:
        dsu.union(u, v)

    components = defaultdict(list)
    for node in range(1, c + 1):
        root = dsu.find(node)
        components[root].append(node)

    component_heaps = {}
    for root in components:
        nodes = components[root]
        heap = nodes.copy()
        heapq.heapify(heap)
        component_heaps[root] = heap

    online = [True] * (c + 1)
    res = []

    for query in queries:
        if query[0] == 1:
            x = query[1]
            if online[x]:
                res.append(x)
            else:
                root = dsu.find(x)
                heap = component_heaps.get(root, [])
                while heap:
                    top = heap[0]
                    if online[top]:
                        res.append(top)
                        break
                    else:
                        heapq.heappop(heap)
                else:
                    res.append(-1)
        else:
            x = query[1]
            online[x] = False

    return res
